import { StyleSpecification } from '@maplibre/maplibre-gl-style-spec';
import { Formatter } from '@dynatrace/strato-components/charts';
import type { BehaviorTrackingProps, DataTestId, MaskingProps, StylingProps } from '@dynatrace/strato-components/core';
import type { TruncationMode } from '@dynatrace/strato-components/typography';
import { ConvertibleUnit, FormatOptions, Unit } from '@dynatrace-sdk/units';
/**
 * Type to disallow al props in a given type
 * @public
 */
export type DisallowAll<T> = {
    [P in keyof T]?: never;
};
/**
 * Props to set the initial view state on the map.
 * @public
 */
export interface ViewState {
    /** Longitude at map center */
    longitude?: number;
    /** Latitude at map center */
    latitude?: number;
    /** Map zoom level */
    zoom?: number;
}
export type ViewStateRequired = Required<ViewState>;
export type BoundingBoxCoords = [number, number, number, number];
/**
 * Type to use in a controlled Map.
 * It disallows the initial state and gives the user complete control over the interactions
 * @public
 */
export interface MapViewControlledProps extends ViewState {
    /**
     * The initial state of the Map. Disallowed on the controlled Map
     */
    initialViewState?: never;
}
/**
 * Type to use in an uncontrolled Map.
 * It allows only setting up an initial state and interactions come out of the box
 * @public
 */
export interface MapViewUncontrolledProps extends DisallowAll<ViewState> {
    /**
     * The initial state of the Map.
     */
    initialViewState?: ViewState;
}
/**
 * Props present in both ways of controlling a Map
 * @public
 */
export interface MapViewBaseProps extends DataTestId, StylingProps, MaskingProps, BehaviorTrackingProps {
    /**
     * Styles of maplibre to be overridden
     */
    mapStyle?: StyleSpecification;
    /**
     * Callback to listen for the changes in the ViewState
     * @param viewState - the new ViewState
     */
    onViewStateChange?: (viewState: ViewState) => void;
    /**
     * Set whether map is loading
     * @defaultValue false
     */
    loading?: boolean;
    /**
     * The height of the chart. If a number is passed, it will be treated as px
     * @defaultValue 400px
     */
    height?: number | string;
    /**
     * The truncation mode to be used as start, middle or end in the long legend
     * labels
     * @defaultValue 'middle'
     */
    truncationMode?: TruncationMode;
    /** Map View formatter options */
    formatter?: Formatter | FormatOptions<Unit, ConvertibleUnit>;
    /**
     * Callback fired when the map context is lost.
     * Browsers have a limit of active WebGL canvas contexts.
     * The map will automatically show an error state, but this callback
     * allows consumers to perform additional actions (e.g., analytics, custom UI).
     */
    onContextLostError?: () => void;
}
/**
 * Props to configure a Map
 * @public
 */
export type MapViewProps = MapViewBaseProps & (MapViewControlledProps | MapViewUncontrolledProps);
/**
 * The Map component ref
 * @public
 */
export interface MapViewRef {
    /** The map component root element */
    readonly element: HTMLDivElement | null;
    /** Downloads map raw data .*/
    downloadData: () => void;
    /** Performs zoom in action on the domain */
    zoomIn: () => void;
    /** Performs zoom out action on the domain */
    zoomOut: () => void;
    /** Performs zoom to fit action on the domain */
    zoomToFit: () => void;
    /** Reset the domain to the default  */
    reset: () => void;
}
